import{_ as s,C as t,o as e,c as r,E as l,ai as n}from"./chunks/framework.B2B1VwZm.js";const u=JSON.parse('{"title":"Proxmox aka PVE - Твій власний датацентр","description":"","frontmatter":{},"headers":[],"relativePath":"pages/selfhost/pve.md","filePath":"pages/selfhost/pve.md","lastUpdated":1762677059000}'),o={name:"pages/selfhost/pve.md"};function p(h,i,c,k,d,m){const a=t("Banner");return e(),r("div",null,[l(a,{text:"Proxmox Virtual Enviroment",image:"/pages/selfhost/pve.png",blur:"1px"}),i[0]||(i[0]=n(`<h1 id="proxmox-aka-pve-твіи-власнии-датацентр" tabindex="-1">Proxmox aka PVE - Твій власний датацентр <a class="header-anchor" href="#proxmox-aka-pve-твіи-власнии-датацентр" aria-label="Permalink to &quot;Proxmox aka PVE - Твій власний датацентр&quot;">​</a></h1><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Proxmox Virtual Environment (скорочено Proxmox VE) — спеціалізований Linux-дистрибутив на базі Debian GNU/Linux, націлений на розгортання і обслуговування віртуальних серверів з використанням LXC і KVM, і здатний виступити в ролі заміни таких продуктів, як VMware vSphere, Microsoft Hyper-V і Citrix Hypervisor. (c) Wikipedia</p></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Це більше буде як нотатки для себе, тому не очікуйте тут багато інформації про користування цією системою</p></div><h2 id="нащо-мені-взагалі-датацентр" tabindex="-1">Нащо мені взагалі датацентр? <a class="header-anchor" href="#нащо-мені-взагалі-датацентр" aria-label="Permalink to &quot;Нащо мені взагалі датацентр?&quot;">​</a></h2><p>Щоб був 😃. Жартую) Це зручний інструмент через котрий можна розвернути відразу декілька віртуальних машин та також лінукс контейнерів котрі схожі десь на Docker, але більше походять на віртуальну машину, а не як засіб щось швидко захостити. Також зручно робити бекапи т.я це віртуальна машина через зручний Веб-Інтерфейс</p><h2 id="пропустимо-що-воно-треба-як-встановити" tabindex="-1">Пропустимо що воно треба, як встановити? <a class="header-anchor" href="#пропустимо-що-воно-треба-як-встановити" aria-label="Permalink to &quot;Пропустимо що воно треба, як встановити?&quot;">​</a></h2><p>Як зрозуміло з вікі - це кастомна збірка Debian GNU/Linux з PVE. Завантажувати образ системи треба на офіційному сайті проекту - <a href="https://proxmox.com/" target="_blank" rel="noreferrer">https://proxmox.com/</a></p><p>Встановлюємо як звичайний Debian на сервер, багато про це казати не буду, там не так тяжко встановити, далі далі далі</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Бажано вибрати файлову систему ZFS, з нею простіше у PVE працювати + бекапи будуть робиться простіше.</p></div><p>Після встановлення, нам треба зайти у веб-морду PVE Proxy так званого та почати робити брудні справи</p><p><img src="https://www.storagereview.com/wp-content/uploads/2023/03/StorageReview-Proxmox-VE-7-4-darktheme.png" alt="PVE Interface"></p><h2 id="різніця-між-звичаиною-віртуальною-машиною-та-lxc-aka-linux-container" tabindex="-1">Різніця між звичайною віртуальною машиною та LXC aka Linux Container <a class="header-anchor" href="#різніця-між-звичаиною-віртуальною-машиною-та-lxc-aka-linux-container" aria-label="Permalink to &quot;Різніця між звичайною віртуальною машиною та LXC aka Linux Container&quot;">​</a></h2><p>Віртуальна машина для багатьох зрозуміла як працює й що це таке, а ось друге це вже схоже, але працює на ядрі хоста й використовує стек ядра для ізоляції системи, прям як у Docker</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>LXC (англ. LinuX Containers) — система віртуалізації на рівні операційної системи для запуску декількох ізольованих примірників ОС Linux на одному комп&#39;ютері. LXC не використовує віртуальні машини, а створює віртуальне оточення з власним простором процесів і мережевим стеком. Усі примірники LXC використовують один примірник ядра ОС. (c) Wikipedia</p></div><h2 id="пост-інсталяція" tabindex="-1">Пост-Інсталяція <a class="header-anchor" href="#пост-інсталяція" aria-label="Permalink to &quot;Пост-Інсталяція&quot;">​</a></h2><h3 id="сommunity-scripts" tabindex="-1"><a href="https://community-scripts.github.io/ProxmoxVE/" target="_blank" rel="noreferrer">Сommunity Scripts</a> <a class="header-anchor" href="#сommunity-scripts" aria-label="Permalink to &quot;[Сommunity Scripts](https://community-scripts.github.io/ProxmoxVE/)&quot;">​</a></h3><p>Ці скрипти допоможуть у налаштування вашого хоумлабу та швидкого запуску self-hosted сервисів, а також налаштують ваш PVE після інсталяції.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Ці скрипти треба вставляти у консоль самого PVE інстансу, де у віртуальний машині чи десь інше</p></div><blockquote><h4 id="pve-post-install" tabindex="-1"><a href="https://community-scripts.github.io/ProxmoxVE/scripts?id=post-pve-install&amp;category=Proxmox+%26+Virtualization" target="_blank" rel="noreferrer">PVE Post Install</a> <a class="header-anchor" href="#pve-post-install" aria-label="Permalink to &quot;[PVE Post Install](https://community-scripts.github.io/ProxmoxVE/scripts?id=post-pve-install&amp;category=Proxmox+%26+Virtualization)&quot;">​</a></h4></blockquote><p>Цей скрипт надає опції для управління репозиторіями Proxmox VE, включаючи відключення Enterprise Repo, додавання або виправлення джерел PVE, увімкнення No-Subscription Repo, додавання тестового Repo, відключення нагадування про підписку, оновлення Proxmox VE та перезавантаження системи.</p><blockquote><h4 id="pve-processor-microcode" tabindex="-1"><a href="https://community-scripts.github.io/ProxmoxVE/scripts?id=microcode&amp;category=Proxmox+%26+Virtualization" target="_blank" rel="noreferrer">PVE Processor Microcode</a> <a class="header-anchor" href="#pve-processor-microcode" aria-label="Permalink to &quot;[PVE Processor Microcode](https://community-scripts.github.io/ProxmoxVE/scripts?id=microcode&amp;category=Proxmox+%26+Virtualization)&quot;">​</a></h4></blockquote><p>Мікрокод процесора — це рівень низькорівневого програмного забезпечення, що працює на процесорі та забезпечує виправлення або оновлення його мікропрограми. Оновлення мікрокоду можуть виправляти апаратні помилки, покращувати продуктивність та посилювати функції безпеки процесора. Важливо зазначити, що доступність механізмів оновлення мікропрограми, таких як Intel Management Engine (ME) або AMD Platform Security Processor (PSP), може відрізнятися залежно від процесора та його конкретної реалізації. Тому рекомендується звернутися до документації вашого процесора, щоб підтвердити, чи можна застосовувати оновлення прошивки через операційну систему.</p><h3 id="звідки-брати-lxc-образи" tabindex="-1">Звідки брати LXC образи? <a class="header-anchor" href="#звідки-брати-lxc-образи" aria-label="Permalink to &quot;Звідки брати LXC образи?&quot;">​</a></h3><p>По-перше, можна завантажувати їх через <a href="https://community-scripts.github.io/ProxmoxVE/" target="_blank" rel="noreferrer">Сommunity Scripts</a>, по-друге, можна напряму з <a href="https://images.linuxcontainers.org/" target="_blank" rel="noreferrer">проекту LXC</a></p><h3 id="нотатки" tabindex="-1">Нотатки <a class="header-anchor" href="#нотатки" aria-label="Permalink to &quot;Нотатки&quot;">​</a></h3><h4 id="перекинути-фаили-директорію-з-хоста-на-lxc" tabindex="-1">Перекинути файли/директорію з хоста на LXC <a class="header-anchor" href="#перекинути-фаили-директорію-з-хоста-на-lxc" aria-label="Permalink to &quot;Перекинути файли/директорію з хоста на LXC&quot;">​</a></h4><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tar</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> -</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">host_fil</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> pct</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> exec</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ID_V</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">M</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;tar xf - -C &lt;vm_path&gt;&#39;</span></span></code></pre></div><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tar</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> -</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Create</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\ \\&amp;\\ </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Advanture.tar</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> pct</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> exec</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 103</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;tar xf - -C /root/&#39;</span></span></code></pre></div><h4 id="змонтувати-директорію-хоста-до-lxc" tabindex="-1">Змонтувати директорію хоста до LXC <a class="header-anchor" href="#змонтувати-директорію-хоста-до-lxc" aria-label="Permalink to &quot;Змонтувати директорію хоста до LXC&quot;">​</a></h4><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pct</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 103</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -mp0</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /host/dir,mp=/container/mount/point</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>-mp0, де 0 - це ID, якщо ви щось змонтували й хочете ще, то ID+1, тобто буде команда &#39;pct set 103 -mp1 ...&#39;</p></div><h4 id="прокинути-відеокарту-для-jellyfin-frigate-etc-amd" tabindex="-1">Прокинути відеокарту для Jellyfin/Frigate/etc (AMD) <a class="header-anchor" href="#прокинути-відеокарту-для-jellyfin-frigate-etc-amd" aria-label="Permalink to &quot;Прокинути відеокарту для Jellyfin/Frigate/etc (AMD)&quot;">​</a></h4><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pct</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 109</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --dev0</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> path=/dev/kfd</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pct</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 109</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --dev1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> path=/dev/dri/renderD128</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Я довго ломав голову як прокинути відеокарту у LXC з Jellyfin, треба танцювати з правами доступу, але оці команди роблять усю брудну роботу за мене 😃</p><p>Драйверів на хостовій системі наче не потрібні, якщо Jellyfin у докері від linuxservers + аддон то треба просто прокинути ці директорії</p></div>`,34))])}const F=s(o,[["render",p]]);export{u as __pageData,F as default};
